VehicleTracker::VehicleTracker(
  const object_model::ObjectModel & object_model, const rclcpp::Time & time,
  const types::DynamicObject & object)
: Tracker(time, object), logger_(rclcpp::get_logger("VehicleTracker")), object_model_(object_model)
{
  // set tracker type based on object model
  if (object_model.type == object_model::ObjectModelType::NormalVehicle) {
    tracker_type_ = TrackerType::NORMAL_VEHICLE;
  } else if (object_model.type == object_model::ObjectModelType::BigVehicle) {
    tracker_type_ = TrackerType::BIG_VEHICLE;
  } else if (object_model.type == object_model::ObjectModelType::Bicycle) {
    tracker_type_ = TrackerType::BICYCLE;
  } else {
    // not supported object model type
    RCLCPP_ERROR(logger_, "Unsupported object model type: %d", static_cast<int>(object_model.type));
    tracker_type_ = TrackerType::UNKNOWN;
  }

  // velocity deviation threshold
  //   if the predicted velocity is close to the observed velocity,
  //   the observed velocity is used as the measurement.
  velocity_deviation_threshold_ = autoware_utils_math::kmph2mps(10);  // [m/s]

  // default anchor point for shape updates
  shape_update_anchor_ = BicycleMotionModel::LengthUpdateAnchor::CENTER;

  if (object.shape.type != autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    // set default initial size
    auto & object_extension = object_.shape.dimensions;
    object_extension.x = object_model_.init_size.length;
    object_extension.y = object_model_.init_size.width;
    object_extension.z = object_model_.init_size.height;
  }
  object_.shape.type = autoware_perception_msgs::msg::Shape::BOUNDING_BOX;

  // set maximum and minimum size
  limitObjectExtension(object_model_);

  // Set motion model parameters
  motion_model_.setMotionParams(
    object_model_.process_noise, object_model_.bicycle_state, object_model_.process_limit);

  // Set initial state
  {
    using autoware_utils_geometry::xyzrpy_covariance_index::XYZRPY_COV_IDX;
    const double x = object.pose.position.x;
    const double y = object.pose.position.y;
    const double yaw = tf2::getYaw(object.pose.orientation);

    auto pose_cov = object.pose_covariance;
    if (!object.kinematics.has_position_covariance) {
      // initial state covariance
      const auto & p0_cov_x = object_model_.initial_covariance.pos_x;
      const auto & p0_cov_y = object_model_.initial_covariance.pos_y;
      const auto & p0_cov_yaw = object_model_.initial_covariance.yaw;

      const double cos_yaw = std::cos(yaw);
      const double sin_yaw = std::sin(yaw);
      const double sin_2yaw = std::sin(2.0 * yaw);
      pose_cov[XYZRPY_COV_IDX::X_X] = p0_cov_x * cos_yaw * cos_yaw + p0_cov_y * sin_yaw * sin_yaw;
      pose_cov[XYZRPY_COV_IDX::X_Y] = 0.5 * (p0_cov_x - p0_cov_y) * sin_2yaw;
      pose_cov[XYZRPY_COV_IDX::Y_Y] = p0_cov_x * sin_yaw * sin_yaw + p0_cov_y * cos_yaw * cos_yaw;
      pose_cov[XYZRPY_COV_IDX::Y_X] = pose_cov[XYZRPY_COV_IDX::X_Y];
      pose_cov[XYZRPY_COV_IDX::YAW_YAW] = p0_cov_yaw;
    }

    double vel_x = 0.0;
    double vel_y = 0.0;
    double vel_x_cov = object_model_.initial_covariance.vel_long;
    double vel_y_cov = object_model_.bicycle_state.init_slip_angle_cov;
    if (object.kinematics.has_twist) {
      vel_x = object.twist.linear.x;
      vel_y = object.twist.linear.y;
    }
    if (object.kinematics.has_twist_covariance) {
      vel_x_cov = object.twist_covariance[XYZRPY_COV_IDX::X_X];
      vel_y_cov = object.twist_covariance[XYZRPY_COV_IDX::Y_Y];
    }

    const double & length = object_.shape.dimensions.x;

    // initialize motion model
    motion_model_.initialize(time, x, y, yaw, pose_cov, vel_x, vel_x_cov, vel_y, vel_y_cov, length);
  }
}

constexpr double kmph2mps(const double kmph)
{
  return kmph * 1000.0 / 3600.0;
}

void Tracker::limitObjectExtension(const object_model::ObjectModel object_model)
{
  auto & object_extension = object_.shape.dimensions;
  // set maximum and minimum size
  object_extension.x = std::clamp(
    object_extension.x, object_model.size_limit.length_min, object_model.size_limit.length_max);
  object_extension.y = std::clamp(
    object_extension.y, object_model.size_limit.width_min, object_model.size_limit.width_max);
  object_extension.z = std::clamp(
    object_extension.z, object_model.size_limit.height_min, object_model.size_limit.height_max);
}

void BicycleMotionModel::setMotionParams(
  object_model::MotionProcessNoise process_noise, object_model::BicycleModelState bicycle_state,
  object_model::MotionProcessLimit process_limit)
{
  // set process noise covariance parameters
  motion_params_.q_stddev_acc_long = process_noise.acc_long;
  motion_params_.q_stddev_acc_lat = process_noise.acc_lat;
  motion_params_.q_cov_acc_long = process_noise.acc_long * process_noise.acc_long;
  motion_params_.q_cov_acc_lat = process_noise.acc_lat * process_noise.acc_lat;
  motion_params_.q_stddev_yaw_rate_min = process_noise.yaw_rate_min;
  motion_params_.q_stddev_yaw_rate_max = process_noise.yaw_rate_max;
  motion_params_.q_cov_slip_rate_min =
    bicycle_state.slip_rate_stddev_min * bicycle_state.slip_rate_stddev_min;
  motion_params_.q_cov_slip_rate_max =
    bicycle_state.slip_rate_stddev_max * bicycle_state.slip_rate_stddev_max;
  motion_params_.q_max_slip_angle = bicycle_state.slip_angle_max;

  // set wheel position parameters
  motion_params_.lf_min = bicycle_state.wheel_pos_front_min;
  motion_params_.lr_min = bicycle_state.wheel_pos_rear_min;
  motion_params_.lf_ratio = bicycle_state.wheel_pos_ratio_front;
  motion_params_.lr_ratio = bicycle_state.wheel_pos_ratio_rear;
  motion_params_.wheel_base_ratio_inv =
    1.0 / (bicycle_state.wheel_pos_ratio_front + bicycle_state.wheel_pos_ratio_rear);

  motion_params_.wheel_pos_ratio =
    (motion_params_.lf_ratio + motion_params_.lr_ratio) / motion_params_.lr_ratio;
  motion_params_.wheel_gamma_front =
    (0.5 - motion_params_.lf_ratio) / (motion_params_.lf_ratio + motion_params_.lr_ratio);
  motion_params_.wheel_gamma_rear =
    (0.5 - motion_params_.lr_ratio) / (motion_params_.lf_ratio + motion_params_.lr_ratio);

  // set bicycle model parameters
  motion_params_.q_cov_length = bicycle_state.length_uncertainty * bicycle_state.length_uncertainty;

  motion_params_.max_vel = process_limit.vel_long_max;
}

bool BicycleMotionModel::initialize(
  const rclcpp::Time & time, const double & x, const double & y, const double & yaw,
  const std::array<double, 36> & pose_cov, const double & vel_long, const double & vel_long_cov,
  const double & vel_lat, const double & vel_lat_cov, const double & length)
{
  const double lr = length * motion_params_.lr_ratio;
  const double lf = length * motion_params_.lf_ratio;
  const double x1 = x - lr * std::cos(yaw);
  const double y1 = y - lr * std::sin(yaw);
  const double x2 = x + lf * std::cos(yaw);
  const double y2 = y + lf * std::sin(yaw);

  // initialize state vector X
  StateVec X;
  X << x1, y1, x2, y2, vel_long, vel_lat * motion_params_.wheel_pos_ratio;

  // initialize covariance matrix P
  StateMat P;
  P.setZero();
  P(IDX::X1, IDX::X1) = pose_cov[XYZRPY_COV_IDX::X_X];
  P(IDX::X1, IDX::Y1) = pose_cov[XYZRPY_COV_IDX::X_Y];
  P(IDX::Y1, IDX::X1) = pose_cov[XYZRPY_COV_IDX::Y_X];
  P(IDX::Y1, IDX::Y1) = pose_cov[XYZRPY_COV_IDX::Y_Y];
  P(IDX::X2, IDX::X2) = pose_cov[XYZRPY_COV_IDX::X_X];
  P(IDX::X2, IDX::Y2) = pose_cov[XYZRPY_COV_IDX::X_Y];
  P(IDX::Y2, IDX::X2) = pose_cov[XYZRPY_COV_IDX::Y_X];
  P(IDX::Y2, IDX::Y2) = pose_cov[XYZRPY_COV_IDX::Y_Y];
  P(IDX::U, IDX::U) = vel_long_cov;
  P(IDX::V, IDX::V) = vel_lat_cov * motion_params_.wheel_pos_ratio;

  return MotionModel::initialize(time, X, P);
}

template <int StateSize, int MeasurementSize>
bool MotionModel<StateSize, MeasurementSize>::initialize(
  const rclcpp::Time & time, const StateVec & X, const StateMat & P)
{
  // initialize Kalman filter
  ekf_.init(X, P);

  // set last_update_time_
  last_update_time_ = time;

  // set initialized flag
  is_initialized_ = true;

  return true;
}

void init(
  const StateVec & x, const ProcessMat & A, const ControlMat & B, const MeasModelMat & C,
  const StateMat & Q, const MeasMat & R, const StateMat & P)
{
  x_ = x;
  A_ = A;
  B_ = B;
  C_ = C;
  Q_ = Q;
  R_ = R;
  P_ = P;
}
